files.content:
.bt-form-field {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.bt-form-field__label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
}

.bt-form-field__label-required {
  color: var(--color-ext-error-bold);
  margin-inline-start: 2px;
}

.bt-form-field__helper {
  font-size: var(--typography-font-size-xs);
  color: var(--text-secondary);
  line-height: var(--typography-line-height-xs);
}

.bt-form-field__error {
  font-size: var(--typography-font-size-xs);
  color: var(--color-ext-error-bold);
  line-height: var(--typography-line-height-xs);
}

import { useId } from 'react';
import { BTFormFieldContext } from './BTFormFieldContext';
import type { BTFormFieldProps } from './BTFormField.types';
import './BTFormField.css';

export function BTFormField({
  label,
  required = false,
  helper,
  error = null,
  id,
  children,
  className,
}: BTFormFieldProps) {
  const autoId = useId();
  const fieldId = id ?? `bt-field-${autoId}`;
  const hasError = Boolean(error);
  const hintId = hasError
    ? `${fieldId}-error`
    : helper
      ? `${fieldId}-hint`
      : undefined;

  return (
    <BTFormFieldContext.Provider value={{ fieldId, error: error ?? null, required, hintId }}>
      <div className={['bt-form-field', className].filter(Boolean).join(' ')}>
        <label htmlFor={fieldId} className="bt-form-field__label">
          {label}
          {required && (
            <span className="bt-form-field__label-required" aria-hidden="true">
              *
            </span>
          )}
        </label>
        {children}
        {hasError ? (
          <p id={`${fieldId}-error`} className="bt-form-field__error" role="alert">
            {error}
          </p>
        ) : helper ? (
          <p id={`${fieldId}-hint`} className="bt-form-field__helper">
            {helper}
          </p>
        ) : null}
      </div>
    </BTFormFieldContext.Provider>
  );
}

BTFormField.displayName = 'BTFormField';

import type React from 'react';

export interface BTFormFieldProps {
  label: string;
  required?: boolean;
  helper?: string;
  error?: string | null;
  id?: string;
  children: React.ReactNode;
  className?: string;
}

export interface BTFormFieldContextValue {
  fieldId: string;
  error: string | null;
  required: boolean;
  hintId: string | undefined;
}

import { createContext, useContext } from 'react';
import type { BTFormFieldContextValue } from './BTFormField.types';

export const BTFormFieldContext = createContext<BTFormFieldContextValue | null>(null);

export function useBTFormField(): BTFormFieldContextValue | null {
  return useContext(BTFormFieldContext);
}

export { BTFormField } from './BTFormField';
export { BTFormFieldContext, useBTFormField } from './BTFormFieldContext';
export type { BTFormFieldProps, BTFormFieldContextValue } from './BTFormField.types';
